-- create "snapshots" table
CREATE TABLE "snapshots" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY (START WITH 60129542144), "create_time" timestamptz NOT NULL, "update_time" timestamptz NOT NULL, "note" text NULL, "household_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "snapshots_households_snapshots" FOREIGN KEY ("household_id") REFERENCES "households" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "snapshot_household_id_create_time" to table: "snapshots"
CREATE INDEX "snapshot_household_id_create_time" ON "snapshots" ("household_id", "create_time");
-- create "snapshot_entries" table
CREATE TABLE "snapshot_entries" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY (START WITH 64424509440), "create_time" timestamptz NOT NULL, "update_time" timestamptz NOT NULL, "liquidity" numeric(36,18) NOT NULL, "investment" numeric(36,18) NOT NULL, "property" numeric(36,18) NOT NULL, "receivable" numeric(36,18) NOT NULL, "liability" numeric(36,18) NOT NULL, "currency_id" bigint NOT NULL, "household_id" bigint NOT NULL, "snapshot_id" bigint NOT NULL, "user_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "snapshot_entries_currencies_snapshot_entries" FOREIGN KEY ("currency_id") REFERENCES "currencies" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "snapshot_entries_households_snapshot_entries" FOREIGN KEY ("household_id") REFERENCES "households" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "snapshot_entries_snapshots_snapshot_entries" FOREIGN KEY ("snapshot_id") REFERENCES "snapshots" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "snapshot_entries_users_snapshot_entries" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "snapshotentry_snapshot_id" to table: "snapshot_entries"
CREATE INDEX "snapshotentry_snapshot_id" ON "snapshot_entries" ("snapshot_id");
-- create index "snapshotentry_snapshot_id_user_id_currency_id" to table: "snapshot_entries"
CREATE UNIQUE INDEX "snapshotentry_snapshot_id_user_id_currency_id" ON "snapshot_entries" ("snapshot_id", "user_id", "currency_id");
